document.addEventListener('DOMContentLoaded',function(){const searchInput=document.getElementById('institution_search');const hiddenIdInput=document.getElementById('iID');const resultsContainer=document.getElementById('institution_results');let timeoutId;searchInput.addEventListener('input',function(){clearTimeout(timeoutId);const query=this.value.trim();if(query.length<4){resultsContainer.style.display='none';if(query.length===0)hiddenIdInput.value='1';return}
timeoutId=setTimeout(()=>{fetch('/lookupInstitutions',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({text:query,csrf_token:document.querySelector('input[name="csrf_token"]').value})}).then(response=>response.json()).then(data=>{resultsContainer.innerHTML='';if(data.length>0){data.forEach(inst=>{const div=document.createElement('div');div.className='autocomplete-item';div.textContent=inst.iname;div.addEventListener('click',function(){searchInput.value=inst.iname;hiddenIdInput.value=inst.iID;resultsContainer.style.display='none'});resultsContainer.appendChild(div)});if(data.length===1)resultsContainer.insertAdjacentHTML('beforeend','<div class="autocomplete-item text-muted">No institutions found...</div>');resultsContainer.style.display='block'}else{resultsContainer.innerHTML='<div class="autocomplete-item text-muted">No institutions found...</div>';resultsContainer.style.display='block'}}).catch(error=>console.error('Error:',error))},500)});document.addEventListener('click',function(e){if(e.target!==searchInput&&!resultsContainer.contains(e.target)){resultsContainer.style.display='none'}})})